const _h = this.helpers;
const fetch = async (url, init = {}) => {
  const opts = { method: init.method || 'GET', url, headers: { ...(init.headers || {}) }, json: true, timeout: 12000, returnFullResponse: false };
  if (opts.headers['Content-Type']) delete opts.headers['Content-Type'];
  if (opts.headers['content-type']) delete opts.headers['content-type'];
  if (init.body !== undefined) {
    if (typeof init.body === 'string') { try { opts.body = JSON.parse(init.body); } catch { opts.body = init.body; } }
    else opts.body = init.body;
  }
  try {
    const data = await _h.httpRequest(opts);
    return { ok: true, status: 200, json: async () => data, text: async () => (typeof data === 'string' ? data : JSON.stringify(data)) };
  } catch (e) {
    const status = (e && e.statusCode) || (e && e.response && e.response.statusCode) || (e && e.cause && e.cause.statusCode) || 500;
    let errBody = (e && e.response && e.response.body) ?? (e && e.cause && e.cause.body) ?? null;
    if (errBody && typeof errBody !== 'string') { try { errBody = JSON.stringify(errBody); } catch { errBody = String(errBody); } }
    if (!errBody && e && e.message) errBody = e.message;
    return { ok: false, status, json: async () => { try { return JSON.parse(errBody); } catch { return errBody; } }, text: async () => String(errBody) };
  }
};

const body = $input.first().json.body || {};
let { branch_id, service_id, from_date, to_date } = body;
if (!branch_id || !service_id) {
  return [{ json: { ok: false, error_code: 'MISSING_PARAMS', message_for_agent: 'Bitte Filiale und Service angeben.' } }];
}
const headers = { apikey: $vars.CARGLASS_SUPABASE_SERVICE_ROLE_KEY, Authorization: 'Bearer ' + $vars.CARGLASS_SUPABASE_SERVICE_ROLE_KEY };
const sb = $vars.CARGLASS_SUPABASE_URL;
async function fetchJson(url) {
  const r = await fetch(url, { headers });
  if (!r.ok) throw new Error('Supabase ' + r.status + ': ' + (await r.text()));
  return await r.json();
}

const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

// Resolve branch_id from slug/name/city if it's not a UUID
if (!UUID_RE.test(String(branch_id))) {
  const term = String(branch_id).trim().toLowerCase();
  const enc = encodeURIComponent(term);
  const found = await fetchJson(`${sb}/rest/v1/branches?select=id,name,city,code,active&or=(code.ilike.${enc},name.ilike.*${enc}*,city.ilike.*${enc}*)&limit=1`);
  if (!found.length) {
    return [{ json: { ok: false, error_code: 'BRANCH_NOT_FOUND', message_for_agent: `Filiale '${branch_id}' nicht gefunden.` } }];
  }
  branch_id = found[0].id;
}

// Resolve service_id from slug/code if not a UUID
if (!UUID_RE.test(String(service_id))) {
  const term = String(service_id).trim().toLowerCase();
  const enc = encodeURIComponent(term);
  // Try exact code match first, then fuzzy on names
  let found = await fetchJson(`${sb}/rest/v1/services?select=id,code,name_de,name_en&code=eq.${enc}&limit=1`);
  if (!found.length) {
    found = await fetchJson(`${sb}/rest/v1/services?select=id,code,name_de,name_en&or=(name_de.ilike.*${enc}*,name_en.ilike.*${enc}*)&limit=1`);
  }
  // Common-language fallbacks
  if (!found.length) {
    const map = { windshield_replacement: 'frontscheibe_ersatz', windshield_repair: 'frontscheibe_reparatur', side_window: 'seitenscheibe', rear_window: 'heckscheibe', calibration: 'kalibrierung', front: 'frontscheibe_ersatz' };
    const guess = map[term];
    if (guess) {
      found = await fetchJson(`${sb}/rest/v1/services?select=id,code&code=eq.${guess}&limit=1`);
    }
  }
  if (!found.length) {
    return [{ json: { ok: false, error_code: 'SERVICE_NOT_FOUND', message_for_agent: `Service '${service_id}' nicht gefunden.` } }];
  }
  service_id = found[0].id;
}

// Normalize / sanitize dates. The LLM frequently returns past dates from its
// training-cutoff. If the requested window is in the past, slide it forward to
// start tomorrow with a 14-day default window.
function parseDate(v) {
  if (!v) return null;
  const s = String(v);
  // accept date-only YYYY-MM-DD
  const dOnly = s.match(/^\d{4}-\d{2}-\d{2}$/);
  const d = new Date(dOnly ? s + 'T00:00:00Z' : s);
  return isNaN(d.getTime()) ? null : d;
}
let fromD = parseDate(from_date);
let toD = parseDate(to_date);
const now = new Date();
const tomorrow = new Date(now.getTime() + 24 * 3600 * 1000);
tomorrow.setUTCHours(7, 0, 0, 0);
if (!fromD || fromD < now) fromD = tomorrow;
if (!toD || toD <= fromD) {
  toD = new Date(fromD.getTime() + 14 * 24 * 3600 * 1000);
}

const from_iso = fromD.toISOString();
const to_iso = toD.toISOString();

const services = await fetchJson(`${sb}/rest/v1/services?id=eq.${service_id}&select=default_duration_minutes`);
const durationMin = services.length ? services[0].default_duration_minutes : 90;
const templates = await fetchJson(`${sb}/rest/v1/slot_templates?branch_id=eq.${branch_id}&service_id=eq.${service_id}`);
const existing = await fetchJson(`${sb}/rest/v1/appointments?branch_id=eq.${branch_id}&scheduled_start=gte.${encodeURIComponent(from_iso)}&scheduled_start=lte.${encodeURIComponent(to_iso)}&status=in.(scheduled,checked_in,in_progress)&select=scheduled_start,scheduled_end`);
const overrides = await fetchJson(`${sb}/rest/v1/slot_overrides?branch_id=eq.${branch_id}&starts_at=lte.${encodeURIComponent(to_iso)}&ends_at=gte.${encodeURIComponent(from_iso)}`);
const holidays = await fetchJson(`${sb}/rest/v1/branch_holidays?branch_id=eq.${branch_id}&date=gte.${from_iso.slice(0,10)}&date=lte.${to_iso.slice(0,10)}`);
const holidaySet = new Set(holidays.map(h => h.date));
const slots = [];
for (let d = new Date(fromD); d <= toD && slots.length < 12; d.setUTCDate(d.getUTCDate() + 1)) {
  const isoDate = d.toISOString().slice(0,10);
  if (holidaySet.has(isoDate)) continue;
  const dow = (d.getUTCDay() + 6) % 7;
  const todays = templates.filter(t => t.day_of_week === dow);
  for (const t of todays) {
    const [oh, om] = String(t.start_time).split(':').map(Number);
    const [ch, cm] = String(t.end_time).split(':').map(Number);
    let cur = new Date(d); cur.setUTCHours(oh, om, 0, 0);
    const close = new Date(d); close.setUTCHours(ch, cm, 0, 0);
    while (cur.getTime() + durationMin * 60000 <= close.getTime() && slots.length < 12) {
      const slotEnd = new Date(cur.getTime() + durationMin * 60000);
      const conflicts = existing.filter(a => {
        const aS = new Date(a.scheduled_start);
        const aE = new Date(a.scheduled_end);
        return aS < slotEnd && aE > cur;
      }).length;
      const overrideConflict = overrides.some(ov => {
        const oS = new Date(ov.starts_at), oE = new Date(ov.ends_at);
        return oS < slotEnd && oE > cur && ov.bays_available === 0;
      });
      if (!overrideConflict && conflicts < t.bays && cur > now) {
        slots.push({ start: cur.toISOString(), end: slotEnd.toISOString() });
      }
      cur = new Date(cur.getTime() + 30 * 60000);
    }
  }
}
return [{ json: { ok: true, data: { branch_id, service_id, duration_minutes: durationMin, from: from_iso, to: to_iso, slots } } }];
